                except Exception:
                    try:
                        cpcs = json.loads((rec2.get('cpc') or '').replace("'", '"'))
                    except Exception:
                        cpcs = []
                for c in cpcs:
                    if isinstance(c, dict) and c.get('first'):
                        code = c.get('code')
                        if code:
                            codes.add(code)
    if codes:
        citing_map.setdefault(assignee_norm, set()).update(codes)

# Prepare outputs
